const toolCall = $json.choices?.[0]?.message?.tool_calls?.[0]?.function || null;
if (!toolCall) {
  throw new Error('Model did not return a tool call');
}

let args = {};
try {
  args = toolCall.arguments ? JSON.parse(toolCall.arguments) : {};
} catch {
  args = {};
}

const service = args.service || 'general consultation';
const date = args.date || new Date(Date.now() + 86400000).toISOString().slice(0, 10);
const time = args.time || '10:00';
const action = args.action || 'check';
const status = action === 'confirm' || action === 'book' ? 'booked' : 'available';

return [{
  json: {
    parsed: args,
    status,
    service,
    date,
    time,
    suggested_slots: [],
    confirmationCode: 'BK-' + Math.random().toString(36).slice(2, 8).toUpperCase(),
    message: 'I can book ' + service + ' on ' + date + ' at ' + time + '.'
  }
}];

const status = $json.status;
const date = $json.date;
const time = $json.time;
const service = $json.service;
let reply;

if (status === 'booked') {
  reply = `Confirmed. Your ${service} is booked for ${date} at ${time}.`;
} else if (status === 'available') {
  reply = `Yes, ${date} at ${time} is available for ${service}. Say "confirm" to book it.`;
} else {
  reply = 'I can book this for you. Please provide the date (YYYY-MM-DD) and time (HH:mm), for example: 2026-04-15 at 11:00.';
}

return [{
  json: {
    reply,
    response_id: $json.response_id || null,
    mode: 'function_calling',
    booking: {
      status,
      service,
      date,
      time,
      suggested_slots: $json.suggested_slots || []
    }
  }
}];
